{
  "executive_summary": "Design a unified API Gateway architecture for a logistics platform serving three distinct consumer types (mobile, B2B partners, internal services). The gateway consolidates the currently fragmented auth and rate-limiting implementations into a single ingress layer with traffic isolation, replacing per-service ad-hoc implementations with a centralized, policy-driven approach. The architecture uses a split-gateway topology — an external gateway for mobile and partner traffic and a separate internal gateway (or mesh sidecar) for service-to-service calls — to enforce the hard isolation requirement between external and internal traffic.",

  "architecture": {
    "components": [
      {
        "name": "External API Gateway",
        "responsibility": "Single ingress point for all external traffic (mobile + B2B). Handles TLS termination, authentication dispatch, rate limiting enforcement, request routing, and request/response transformation. Runs as a horizontally-scaled stateless cluster.",
        "boundaries": "Accepts only traffic from the public internet or partner VPN. Never routes to internal-only services. All requests must pass through the auth pipeline before reaching upstream services."
      },
      {
        "name": "Internal API Gateway / Service Mesh Sidecar",
        "responsibility": "Routes internal service-to-service traffic. Enforces network-level isolation (no external traffic reaches this plane). Provides service discovery, circuit breaking, and observability for internal calls. No authentication overhead — relies on network-level trust within the private subnet.",
        "boundaries": "Only reachable from within the private network / Kubernetes cluster. Physically or logically separated from external gateway at the network level (separate listeners, separate ports, or separate deployment)."
      },
      {
        "name": "Auth Pipeline",
        "responsibility": "A composable middleware chain within the external gateway. Dispatches to the correct authentication strategy based on consumer type: JWT/OAuth2 for mobile, API key + HMAC for B2B partners. Attaches a normalized identity context (consumer type, tenant ID, rate-limit tier) to the request before forwarding upstream.",
        "boundaries": "Stateless — validates tokens against a shared secret / JWKS endpoint. Does not own user/partner data; delegates to the Identity Service for token issuance and key management."
      },
      {
        "name": "Rate Limiter",
        "responsibility": "Enforces per-consumer rate limits: 100 req/min per user (mobile), 1,000 req/min per partner (B2B). Uses a sliding window or token bucket algorithm backed by a shared Redis counter store. Returns 429 with Retry-After header on breach.",
        "boundaries": "Runs as a gateway plugin/filter, not as a separate network hop. Reads consumer identity from the auth-enriched request context. Rate limit policies are externalized in configuration, not hardcoded."
      },
      {
        "name": "Webhook Dispatcher",
        "responsibility": "Manages webhook subscriptions for B2B partners. Consumes domain events from an internal message broker, transforms them into partner-specific payloads, and delivers them with exponential backoff retry, HMAC signature verification, and delivery status tracking.",
        "boundaries": "Downstream of the internal event bus. Does not handle inbound API traffic. Partner webhook URLs are stored in a dedicated webhook registry. Isolated failure domain — webhook delivery failures do not affect API availability."
      },
      {
        "name": "Identity Service",
        "responsibility": "Issues and manages authentication credentials: OAuth2 tokens for mobile users, API keys for B2B partners. Provides JWKS endpoint for gateway token validation. Manages partner onboarding and key rotation.",
        "boundaries": "Internal service, not directly exposed externally. The gateway delegates credential validation here (via JWKS/introspection), but the hot path uses local JWT validation to avoid per-request network calls."
      },
      {
        "name": "Gateway Admin / Control Plane",
        "responsibility": "Manages gateway configuration: route definitions, rate limit policies, auth policies, partner onboarding. Provides a declarative API for infrastructure-as-code. Pushes configuration to gateway instances.",
        "boundaries": "Accessible only to platform operators. Changes are versioned and auditable. Configuration propagation is eventually consistent (seconds, not minutes)."
      }
    ],
    "interfaces": [
      {
        "from": "Mobile App",
        "to": "External API Gateway",
        "contract": "HTTPS with Bearer JWT in Authorization header. Gateway validates JWT signature via JWKS, extracts user_id for rate limiting. Returns standard error envelope on 401/429.",
        "coupling_type": "loose — standard OAuth2 Bearer token protocol"
      },
      {
        "from": "Partner Integration",
        "to": "External API Gateway",
        "contract": "HTTPS with API key in X-API-Key header + optional HMAC signature in X-Signature header. Gateway validates key against Identity Service cache, extracts partner_id for rate limiting. Versioned API paths (/v1/, /v2/).",
        "coupling_type": "loose — API key is a shared secret, no session state"
      },
      {
        "from": "External API Gateway",
        "to": "Auth Pipeline",
        "contract": "In-process middleware chain. Request enters pipeline, auth strategy is selected based on route metadata (consumer_type tag on the route). Pipeline enriches request context with { consumer_type, tenant_id, rate_limit_tier }.",
        "coupling_type": "tight — co-deployed as gateway plugins, but composable and independently testable"
      },
      {
        "from": "External API Gateway",
        "to": "Rate Limiter",
        "contract": "In-process filter. Reads tenant_id and rate_limit_tier from enriched request context. Increments counter in Redis (key: rl:{tier}:{tenant_id}, window: 60s). Returns 429 with Retry-After if limit exceeded.",
        "coupling_type": "tight — co-deployed plugin with external dependency on Redis"
      },
      {
        "from": "External API Gateway",
        "to": "Upstream Services",
        "contract": "HTTP/gRPC with X-Consumer-Type, X-Tenant-Id, X-Request-Id headers injected by gateway. Upstream services trust these headers (gateway is the only ingress). Services no longer perform their own auth.",
        "coupling_type": "loose — header-based context propagation, no shared libraries"
      },
      {
        "from": "Internal Services",
        "to": "Internal API Gateway / Mesh",
        "contract": "HTTP/gRPC within private network. No auth headers required. Service discovery via DNS or service registry. Circuit breaker and retry policies applied at mesh level.",
        "coupling_type": "loose — network-level routing, services are unaware of mesh"
      },
      {
        "from": "Internal Event Bus",
        "to": "Webhook Dispatcher",
        "contract": "Async message consumption (e.g., Kafka/SQS). Events follow a canonical envelope: { event_type, aggregate_id, timestamp, payload }. Dispatcher maps event_type to partner subscriptions.",
        "coupling_type": "loose — async, schema-versioned events"
      },
      {
        "from": "Gateway Admin",
        "to": "External API Gateway",
        "contract": "Declarative configuration push (e.g., Kubernetes CRDs, or admin API). Route and policy definitions are YAML/JSON. Hot-reload without gateway restart.",
        "coupling_type": "loose — configuration-driven, no code coupling"
      }
    ],
    "data_flow": "External request → DNS/LB → External API Gateway → [TLS termination] → [Route matching] → [Auth Pipeline: select strategy by route tag → validate credential → enrich context] → [Rate Limiter: check counter in Redis → allow or 429] → [Request transformation: strip external headers, inject trusted headers] → Upstream Service → Response flows back through gateway (optional response transformation, metrics emission). Internal service-to-service traffic bypasses the external gateway entirely, flowing through the internal mesh/gateway on a separate network plane. Webhook flow: Upstream Service emits domain event → Message Broker → Webhook Dispatcher → Partner endpoint (with retry).",
    "patterns_used": [
      {
        "pattern": "Split Gateway / BFF Topology",
        "rationale": "Hard requirement to isolate internal traffic from external. A single gateway serving both would require complex ACLs and increase blast radius. Two separate gateways (external + internal mesh) provide physical isolation with independent scaling and failure domains."
      },
      {
        "pattern": "Chain of Responsibility (Auth + Rate Limit Pipeline)",
        "rationale": "Auth and rate limiting are cross-cutting concerns that must execute in a strict order (authenticate → identify → rate limit → route). A composable middleware chain allows each concern to be developed, tested, and toggled independently."
      },
      {
        "pattern": "Strangler Fig (Migration Strategy)",
        "rationale": "Services currently handle their own auth. Migrating all services to gateway-managed auth at once is risky. Route traffic through the gateway incrementally — service by service — while keeping existing auth as a fallback during migration."
      },
      {
        "pattern": "Token Bucket / Sliding Window Rate Limiting",
        "rationale": "Sliding window counters in Redis provide accurate per-tenant rate limiting with minimal latency overhead (~1ms per check). Token bucket is the alternative if burst tolerance is desired. Both are well-understood and operationally simple."
      },
      {
        "pattern": "Async Webhook Delivery with Outbox",
        "rationale": "Webhook delivery must not block API responses. Consuming events from a message broker decouples delivery from the request path and enables reliable retry with exponential backoff."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "API Gateway / Traffic Management",
        "classification": "supporting",
        "aggregates": ["Route", "RateLimitPolicy", "ConsumerIdentity"]
      },
      {
        "name": "Identity & Access Management",
        "classification": "generic",
        "aggregates": ["User", "Partner", "APIKey", "OAuthToken"]
      },
      {
        "name": "Partner Integration",
        "classification": "supporting",
        "aggregates": ["WebhookSubscription", "WebhookDelivery", "PartnerConfiguration"]
      },
      {
        "name": "Logistics Core",
        "classification": "core",
        "aggregates": ["Shipment", "Order", "Route (logistics)"]
      }
    ],
    "context_map": [
      {
        "upstream": "Identity & Access Management",
        "downstream": "API Gateway / Traffic Management",
        "relationship": "Open Host Service — Identity exposes JWKS and key-validation endpoints that the gateway consumes. Gateway conforms to Identity's token format."
      },
      {
        "upstream": "Logistics Core",
        "downstream": "Partner Integration",
        "relationship": "Published Language — Core publishes domain events in a canonical schema. Webhook Dispatcher consumes and transforms them per partner. ACL in the dispatcher prevents partner-specific concerns from leaking into core."
      },
      {
        "upstream": "API Gateway / Traffic Management",
        "downstream": "Logistics Core",
        "relationship": "Conformist — Gateway routes requests to core services without transforming the domain model. Core services define their own API contracts; gateway is a transparent proxy with auth enrichment."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Split external/internal gateways instead of a single unified gateway",
      "gains": "Hard network isolation between external and internal traffic. Independent scaling (external gateway scales with user traffic, internal mesh scales with service count). Reduced blast radius — external gateway compromise does not expose internal traffic.",
      "sacrifices": "Two systems to operate and monitor instead of one. Configuration duplication for shared policies (e.g., timeouts, retries). Slightly higher operational complexity.",
      "alternatives_considered": ["Single gateway with ACL-based isolation (rejected: ACL misconfiguration risk is too high for the isolation requirement)", "Service mesh only with ingress controller (viable but less control over B2B-specific features like API key management and webhook delivery)"]
    },
    {
      "decision": "Gateway-level rate limiting with Redis vs per-service rate limiting",
      "gains": "Consistent enforcement across all services. Single place to configure and monitor limits. Protects upstream services from overload before requests reach them.",
      "sacrifices": "Redis becomes a critical dependency on the hot path. If Redis is unavailable, must decide: fail open (risk overload) or fail closed (reject all traffic). Adds ~1-2ms latency per request.",
      "alternatives_considered": ["Local in-memory rate limiting per gateway instance (rejected: inaccurate in multi-instance deployments, allows limit * N actual throughput)", "Per-service rate limiting (rejected: exactly the inconsistent approach being replaced)"]
    },
    {
      "decision": "Local JWT validation at gateway vs token introspection",
      "gains": "No per-request network call to Identity Service. Sub-millisecond validation. Identity Service is not on the critical path for every request.",
      "sacrifices": "Token revocation is not immediate — must wait for token expiry or maintain a short-lived token + refresh pattern. Adds complexity around JWKS key rotation.",
      "alternatives_considered": ["Token introspection endpoint (rejected for mobile due to latency at scale; acceptable as fallback for B2B if needed)", "Short-lived tokens (5 min) with refresh (recommended complement to local validation)"]
    },
    {
      "decision": "Strangler fig migration vs big-bang cutover",
      "gains": "Lower risk — services migrate incrementally. Existing auth continues to work during transition. Team can learn and iterate on gateway configuration.",
      "sacrifices": "Temporary period where some services use gateway auth and others use legacy auth. Must maintain both systems during migration. Requires careful routing configuration.",
      "alternatives_considered": ["Big-bang cutover (rejected: too risky with inconsistent existing implementations)", "Parallel run with shadow traffic (viable complement but not sufficient alone)"]
    }
  ],

  "flexibility_points": [
    {
      "area": "Auth Strategy Selection",
      "evolution_path": "New consumer types (e.g., IoT devices, third-party marketplace) can be added by implementing a new auth strategy plugin and tagging routes. No gateway code changes needed — just configuration."
    },
    {
      "area": "Rate Limit Policies",
      "evolution_path": "Rate limits are externalized in configuration per consumer tier. Adding new tiers (e.g., premium partners at 5,000 req/min) or changing limits is a config change, not a code change."
    },
    {
      "area": "Webhook Event Types",
      "evolution_path": "New domain events can be exposed to partners by adding a subscription mapping in the Webhook Dispatcher. The canonical event schema allows new event types without changing the delivery infrastructure."
    },
    {
      "area": "Gateway Technology",
      "evolution_path": "The architecture is technology-agnostic. Can be implemented with Kong, Envoy/Istio, AWS API Gateway, or custom. The plugin/filter model means switching gateway tech preserves the logical architecture."
    }
  ],

  "rigidity_points": [
    {
      "area": "External/Internal Traffic Isolation",
      "reason": "This is a security invariant, not a flexibility point. Internal services must never be reachable from external traffic. This must be enforced at the network level (separate listeners, separate subnets, firewall rules) — not just at the application level."
    },
    {
      "area": "Auth Pipeline Ordering",
      "reason": "Authentication must always execute before rate limiting (you need identity to apply per-tenant limits). Rate limiting must always execute before routing (protect upstream services). This ordering is a structural invariant of the gateway."
    },
    {
      "area": "Trusted Header Contract",
      "reason": "Upstream services must trust X-Consumer-Type and X-Tenant-Id headers injected by the gateway. This means the gateway must strip these headers from incoming external requests to prevent spoofing. This stripping behavior is a security invariant."
    }
  ],

  "risks": [
    {
      "risk": "Redis failure on the rate-limiting hot path causes either cascading overload (fail open) or total outage (fail closed)",
      "severity": "high",
      "mitigation": "Deploy Redis in HA mode (Sentinel or Cluster). Implement a local fallback: if Redis is unreachable for >500ms, fall back to in-memory approximate rate limiting per gateway instance with degraded accuracy. Alert on Redis connectivity issues. Set a clear policy: fail open with aggressive monitoring for the first 30 seconds, then fail closed if Redis remains unavailable."
    },
    {
      "risk": "Migration period with dual auth (gateway + legacy per-service) creates confusion and potential security gaps",
      "severity": "high",
      "mitigation": "Maintain a migration tracker listing each service's auth status (legacy/gateway/both). During migration, services that have moved to gateway auth must reject requests without trusted gateway headers. Run parallel validation (gateway + legacy) in shadow mode before cutting over each service."
    },
    {
      "risk": "Gateway becomes a single point of failure for all external traffic",
      "severity": "critical",
      "mitigation": "Deploy gateway as a horizontally-scaled stateless cluster behind a load balancer. Health checks with automatic instance replacement. Blue-green or canary deployments for gateway configuration changes. Maintain sub-second failover. Load test at 3x peak traffic."
    },
    {
      "risk": "Header spoofing — external client sends X-Consumer-Type or X-Tenant-Id headers to impersonate another consumer type",
      "severity": "critical",
      "mitigation": "Gateway must unconditionally strip all trusted internal headers (X-Consumer-Type, X-Tenant-Id, X-Request-Id) from incoming external requests before the auth pipeline runs. This is a non-negotiable security control. Add integration tests that verify spoofed headers are stripped."
    },
    {
      "risk": "Webhook delivery backlog during partner endpoint outages creates unbounded queue growth",
      "severity": "medium",
      "mitigation": "Implement exponential backoff with a max retry count (e.g., 8 retries over 24 hours). Dead-letter queue for exhausted retries. Per-partner circuit breaker to stop attempting delivery to consistently failing endpoints. Dashboard for webhook delivery health per partner."
    },
    {
      "risk": "JWT token revocation lag — compromised mobile tokens remain valid until expiry",
      "severity": "medium",
      "mitigation": "Keep token TTL short (5 minutes). Use refresh tokens with longer TTL stored server-side (revocable). For emergency revocation, maintain a small bloom filter or deny-list in Redis checked at the gateway (adds minimal latency, covers the revocation gap)."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Phase 1 (Weeks 1-2): Deploy external API gateway (Kong or Envoy-based) with TLS termination and basic routing. No auth yet — just transparent proxying to validate routing works. Phase 2 (Weeks 3-4): Implement auth pipeline — JWT validation for mobile routes, API key validation for partner routes. Deploy Identity Service JWKS endpoint. Add header stripping and enrichment. Phase 3 (Weeks 5-6): Add Redis-backed rate limiting with the two tiers (100/min mobile, 1,000/min partner). Add fallback behavior. Phase 4 (Weeks 7-8): Migrate services one by one using strangler fig — start with lowest-traffic service, validate, then proceed. Remove legacy auth from each migrated service. Phase 5 (Weeks 9-10): Deploy Webhook Dispatcher for B2B partners. Connect to event bus. Partner onboarding workflow. Throughout: Internal service mesh (Istio/Linkerd or lightweight internal gateway) deployed in parallel from Week 1, with network policies enforcing external/internal isolation.",
    "files_to_create_or_modify": [
      "infrastructure/gateway/external-gateway.yaml — Gateway deployment, listeners, TLS config",
      "infrastructure/gateway/routes/ — Per-service route definitions with consumer_type tags",
      "infrastructure/gateway/plugins/auth-pipeline.lua (or .go/.wasm) — Auth strategy dispatcher",
      "infrastructure/gateway/plugins/rate-limiter.lua — Rate limit filter with Redis backend",
      "infrastructure/gateway/policies/rate-limits.yaml — Externalized rate limit tiers",
      "infrastructure/network-policies/ — Kubernetes NetworkPolicies enforcing external/internal isolation",
      "services/identity-service/ — JWKS endpoint, API key management, token issuance",
      "services/webhook-dispatcher/ — Event consumer, delivery engine, subscription registry",
      "infrastructure/redis/ — Redis HA deployment for rate limiting counters"
    ],
    "patterns_to_follow": "Use declarative configuration for all gateway policies (routes, rate limits, auth rules). Follow the plugin/filter model of your chosen gateway technology — avoid custom forking. All gateway configuration should be version-controlled and deployed via CI/CD. Use canary deployments for gateway changes. Follow the sidecar pattern for internal mesh if using Istio/Envoy.",
    "pitfalls_to_avoid": [
      "Do NOT put business logic in the gateway — it is an infrastructure concern only (auth, rate limiting, routing, observability). Business validation stays in services.",
      "Do NOT use a shared database between the gateway and upstream services — the gateway should be stateless except for Redis counters and cached JWKS keys.",
      "Do NOT implement rate limiting with local counters only in a multi-instance gateway deployment — you will get limit * N effective throughput.",
      "Do NOT skip header stripping — this is the most common API gateway security vulnerability.",
      "Do NOT migrate all services to gateway auth simultaneously — use strangler fig to reduce risk.",
      "Do NOT make the Identity Service synchronous on the hot path — use local JWT validation with cached JWKS keys.",
      "Do NOT expose internal service endpoints through the external gateway 'temporarily' — enforce isolation from day one with network policies."
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 85,
    "high_confidence_areas": [
      "Split gateway topology for external/internal isolation — this is the correct approach given the hard isolation requirement",
      "Auth pipeline design with JWT for mobile and API keys for B2B — these are industry-standard patterns",
      "Redis-backed rate limiting with sliding window — well-proven at scale",
      "Strangler fig migration strategy — the only safe way to migrate from inconsistent per-service auth"
    ],
    "low_confidence_areas": [
      "Specific gateway technology choice (Kong vs Envoy vs cloud-native) — depends on team expertise and infrastructure platform, which are not specified",
      "Internal mesh vs lightweight internal gateway — depends on whether team is already running Kubernetes with service mesh capability",
      "Webhook delivery SLA and retry policy specifics — depend on partner contracts not specified"
    ],
    "assumptions": [
      "The platform runs on Kubernetes or a similar container orchestration platform that supports network policies",
      "Redis (or an equivalent low-latency shared store) is available or can be deployed for rate limiting",
      "The team has operational capacity to manage a gateway deployment (monitoring, upgrades, configuration management)",
      "Mobile app uses a standard OAuth2 flow with refresh tokens",
      "B2B partners can adopt API key authentication with webhook consumption",
      "An internal message broker (Kafka, SQS, etc.) exists or can be deployed for webhook event sourcing"
    ]
  }
}

